Function: #include <string.h>
#include <stdlib.h>
#include <stdbool.h>
#include "ioctl_handler.h"
#include "device.h"

#define MAX_CONFIG_KEYS 10

typedef struct {
    char *key;
    int value;
} ConfigEntry;

static ConfigEntry config_table[MAX_CONFIG_KEYS];
static int config_count = 0;

bool ioctl_handler_init(void) {
    // Example configurations
    config_table[config_count].key = strdup("mode");
    config_table[config_count].value = 1;
    config_count++;

    config_table[config_count].key = strdup("threshold");
    config_table[config_count].value = 50;
    config_count++;

    config_table[config_count].key = strdup("enabled");
    config_table[config_count].value = 1;
    config_count++;

    return true;
}

int ioctl_get_config(const char *key) {
    for (int i = 0; i < config_count; i++) {
        if (strcmp(config_table[i].key, key) == 0) {
            return config_table[i].value;
        }
    }
    printf("ioctl: GET_CONFIG: key '%s' not found\n", key);
    return -1; // Key not found
}

void ioctl_set_config(const char *key, int value) {
    for (int i = 0; i < config_count; i++) {
        if (strcmp(config_table[i].key, key) == 0) {
            config_table[i].value = value;
            return;
        }
    }

    if (config_count < MAX_CONFIG_KEYS) {
        config_table[config_count].key = strdup(key);
        config_table[config_count].value = value;
        config_count++;
    } else {
        // Table full, cannot add more
        printf("ioctl: SET_CONFIG: config table full\n");
    }
}

void ioctl_handler_cleanup(void) {
    for (int i = 0; i < config_count; i++) {
        free(config_table[i].key);
    }
    config_count = 0;
}

int ioctl_handler(unsigned long request, void *data) {
    if (data == NULL) {
        printf("ioctl: NULL request pointer\n");
        return -1;
    }

    IoctlData *ioctl_data = (IoctlData *)data;

    switch (request) {
        case IOCTL_GET_CONFIG:
            if (ioctl_data->key == NULL) {
                printf("ioctl: GET_CONFIG: NULL key pointer\n");
                return -1;
            }
            ioctl_data->value = ioctl_get_config(ioctl_data->key);
            return (ioctl_data->value != -1) ? 0 : -1;

        case IOCTL_SET_CONFIG:
            if (ioctl_data->key == NULL) {
                printf("ioctl: SET_CONFIG: NULL key pointer\n");
                return -1;
            }
            ioctl_set_config(ioctl_data->key, ioctl_data->value);
            return 0;

        default:
            return -1; // Unsupported request
    }
}
